blocks.body:
{
    "level": "A2–B1",
    "intro": "]W tym temacie nauczysz się <strong>zaimków zwrotnych</strong> – słów, które pokazują, że akcja powraca do self.",
    "rules": [
        {
            "label": "-SELF/-SELVES",
            "color": "emerald",
            "text": "<strong>Forma:</strong> -self (liczba pojedyncza), -self (liczba mnoga)",
            "example": "ja, ty, on, my sami, sami"
        },
        {
            "label": "Odruchowe use",
            "color": "blue",
            "text": "<strong>Działanie na sobie:</strong> topic = object",
            "example": "Uczyłem się hiszpańskiego. Zacięła się."
        },
        {
            "label": "Ematyczne użycie",
            "color": "amber",
            "text": "<strong>Wzmocnienie:</strong> sam, sama, sami",
            "example": "Sam to zrobiłem. Przyszedł sam szef."
        }
    ]
}

{
    "title": "1. Pełna tabela zaimków zwrotnych",
    "intro": "Wszystkie zaimki zwrotne kończą się na -self lub -selves:",
    "rows": [
        {
            "en": "Ja → siebie",
            "ua": "Ja → siebie",
            "note": "Zraniłem się."
        },
        {
            "en": "ty → siebie (liczba pojedyncza)",
            "ua": "ty → siebie (self)",
            "note": "Zrobiłeś to sam."
        },
        {
            "en": "on → siebie",
            "ua": "on → siebie",
            "note": "Zaciął się."
        },
        {
            "en": "ona → sama",
            "ua": "ona → sama",
            "note": "Nauczyła się sama."
        },
        {
            "en": "to → sam",
            "ua": "to → sam",
            "note": "Kot sam się oczyścił."
        },
        {
            "en": "my → sami",
            "ua": "my → siebie",
            "note": "We enjoyed ourselves."
        },
        {
            "en": "you → yourselves (plural)",
            "ua": "ви → себе (самі)",
            "note": "You all did it yourselves."
        },
        {
            "en": "they → themselves",
            "ua": "вони → себе (самі)",
            "note": "Przedstawili się."
        }
    ],
    "warning": "📌 -self = liczba pojedyncza, -self = liczba mnoga."
}

{
    "title": "2. Użycie zwrotne - działanie na siebie",
    "sections": [
        {
            "label": "Gdy podmiot = przedmiot",
            "color": "emerald",
            "description": "Zaimków zwrotnych używamy, gdy <strong>osoba, która działa i ta, do której skierowana jest akcja, to ta sama osoba</strong>.",
            "examples": [
                {
                    "en": "Ranim się.",
                    "ua": "Ranizuję się "
                },
                {
                    "en": "Pocięła się nożem.",
                    "ua": "Pocięła się nożem."
                },
                {
                    "en": "Sam nauczył się grać na gitarze.",
                    "ua": "Sam nauczył się grać na gitarze."
                },
                {
                    "en": "Na imprezie dobrze się bawiliśmy: zaimki:",
                    "ua": "Ми добре провели час на вечірці."
                },
                {
                    "en": "They introduced themselves.",
                    "ua": "Вони представилися."
                }
            ]
        },
        {
            "label": "Типові дієслова з reflexive",
            "color": "sky",
            "description": "Деякі дієслова часто використовуються з зворотними займенниками:",
            "examples": [
                {
                    "en": "zranić się - aby się zranić",
                    "ua": "Zraniłem się grając w piłkę nożną."
                },
                {
                    "en": "skaleć się - aby się skaleczyć",
                    "ua": "Uważaj, żeby się nie skaleczyć!"
                },
                {
                    "en": "naucz się - uczyć siebie",
                    "ua": "Nauczyła się hiszpańskiego."
                },
                {
                    "en": "baw się dobrze – baw się dobrze",
                    "ua": "Enjoy yourselves at the concert!"
                },
                {
                    "en": "introduce yourself — представитися",
                    "ua": "Let me introduce myself."
                },
                {
                    "en": "pomoc sobie - częstuj się",
                    "ua": "Poczęstuj się ciastem."
                }
            ]
        },
        {
            "label": "Spójrz na siebie",
            "color": "purple",
            "description": "W przypadku czasowników takich jak <strong>patrz, rozmawiaj, wierz</strong> używamy również zwrotu zwrotnego.",
            "examples": [
                {
                    "en": "Spójrz na siebie w lustrze.",
                    "ua": "Spójrz na siebie w lustrze."
                },
                {
                    "en": "Ona czasami mówi do siebie.",
                    "ua": "Czasami mówi do siebie."
                },
                {
                    "en": "Powinieneś uwierzyć w siebie.",
                    "ua": "Powinieneś uwierzyć w siebie siebie."
                },
                {
                    "en": "Śmiali się z siebie.",
                    "ua": "Śmiali się z siebie."
                }
            ]
        }
    ]
}

{
    "title": "3. Użycie emfatyczne – wzmocnienie (on sam, ona sama, siebie)",
    "sections": [
        {
            "label": "Dla wzmocnienia",
            "color": "amber",
            "description": "Zaimków odwrotnych używa się także dla <strong>wzmocnienia</strong> – aby podkreślić, że to ta osoba wykonała czynność (a nie ktoś inny).",
            "examples": [
                {
                    "en": "Ja to zrobiłem sam.",
                    "ua": "Zrobiłem to sam (bez niczyjej pomocy)."
                },
                {
                    "en": "Sama ugotowała obiad.",
                    "ua": "Sama ugotowała obiad."
                },
                {
                    "en": "Na wydarzenie przybył sam prezydent.",
                    "ua": "Prezydent sam przyjechał wydarzenie."
                },
                {
                    "en": "Sami zbudowaliśmy ten dom.",
                    "ua": " ten dom."
                }
            ]
        },
        {
            "label": "Wyraźna pozycja",
            "color": "blue",
            "description": "W użyciu empatycznym zaimek zwrotny może znajdować się <strong>bezpośrednio po podmiocie</strong> lub <strong>na końcu zdania zdanie</strong>.",
            "examples": [
                {
                    "en": "Sam to widziałem. = Sam to widziałem.",
                    "ua": "Sam to widziałem."
                },
                {
                    "en": "Sam szef zadzwonił. = Szef zadzwonił sam.",
                    "ua": "Szef zadzwonił sam."
                },
                {
                    "en": "Ona sama mi powiedziała. = Sama mi powiedziała.",
                    "ua": "Sama mi powiedziała."
                }
            ],
            "note": "📌 Obie pozycje są prawidłowe – po temacie lub na końcu."
        },
        {
            "label": "Różnica: refleksyjna vs empatyczna",
            "color": "purple",
            "description": "<strong>Refleksyjna</strong> jest obowiązkowa (działanie na siebie). <strong>Wyraźny</strong> jest opcjonalny (dla podkreślenia).",
            "examples": [
                {
                    "en": "Zraniłem się. (odruchowe - obowiązkowe)",
                    "ua": "Zraniłem się."
                },
                {
                    "en": "Zrobiłem to sam. (stanowczy – możliwy: zrobiłem to)",
                    "ua": "Zrobiłem to sam."
                }
            ],
            "note": "Odruchowy – konieczny. Stanowczy – dla podkreślenia."
        }
    ]
}

{
    "title": "4. Sam, dla siebie, dla siebie",
    "sections": [
        {
            "label": "Samotnie – niezależnie",
            "color": "emerald",
            "description": "<strong>Przez + refleksyjny</strong> oznacza <strong>samodzielnie</strong> (bez pomocy) lub <strong>sam</strong> (sam).",
            "examples": [
                {
                    "en": "Zrobiłem to przez sam.",
                    "ua": "Zrobiłem to sam (bez pomocy)."
                },
                {
                    "en": "Mieszka sama.",
                    "ua": "Mieszka sama (sam)."
                },
                {
                    "en": "Czy możesz to zrobić sam?",
                    "ua": "Możesz to zrobić sam?"
                },
                {
                    "en": "Poszedł sam do kina.",
                    "ua": "Poszedł do kina sam (jedno)."
                }
            ],
            "note": "📌 Sam = sam lub bez pomocy."
        },
        {
            "label": "Dla siebie",
            "color": "blue",
            "description": "<strong>Dla + refleksyjny</strong> oznacza <strong>dla siebie</strong>.",
            "examples": [
                {
                    "en": "Kup coś dla siebie.",
                    "ua": "Kup coś dla "
                },
                {
                    "en": "Zachowaj to dla siebie.",
                    "ua": "Zostaw to dla siebie."
                },
                {
                    "en": "Ja to zrobiłem ciasto dla siebie.",
                    "ua": "Piekłam to ciasto dla siebie."
                }
            ]
        },
        {
            "label": "Do siebie — do siebie, dla siebie",
            "color": "sky",
            "description": "<strong>Do + refleksyjnego</strong> często w wyrażeniach takich jak „powiedz sobie”, „trzymaj dla siebie”.",
            "examples": [
                {
                    "en": "Zachowaj to dla siebie.",
                    "ua": "Zachowaj to dla siebie (nie rób tego) powiedz)."
                },
                {
                    "en": "Powiedziałem sobie...",
                    "ua": "Powiedziałem sobie..."
                },
                {
                    "en": "Szeptała do siebie.",
                    "ua": "Szepnęła do siebie."
                }
            ]
        }
    ]
}

{
    "title": "5. Kiedy NIE używać zaimka zwrotnego",
    "sections": [
        {
            "label": "W przypadku niektórych czasowników NIE jest to konieczne",
            "color": "rose",
            "description": "Niektóre czasowniki w języku angielskim <strong>NIE potrzebują</strong> zaimka zwrotnego (w przeciwieństwie do ukraińskiego!).",
            "examples": [
                {
                    "en": "Czuję się dobrze. (✓)",
                    "ua": "Czuję się dobrze."
                },
                {
                    "en": "Czuję się dobrze. (✗)",
                    "ua": "BŁĄD"
                },
                {
                    "en": "Ubrała się. (✓)",
                    "ua": "Ubrała się."
                },
                {
                    "en": "Ubrała się. (✗ we współczesnym angielskim)",
                    "ua": "staromodny"
                },
                {
                    "en": "Spotkaliśmy się o 17:00. (✓)",
                    "ua": "Spotkaliśmy się o 17:00."
                },
                {
                    "en": "Poznaliśmy się. (✗)",
                    "ua": "BŁĄD"
                }
            ],
            "note": "📌 Poczuj się, ubierz, poznaj, umyj się, gol — bez odruchu!"
        },
        {
            "label": "Umyj się, gol — przypadek szczególny",
            "color": "amber",
            "description": "<strong>Umyj się</strong> i <strong>gol się</strong> zwykle bez odruchowe, ale można je dodać dla wzmocnienia.",
            "examples": [
                {
                    "en": "Pielę codziennie. (✓ oczywiście)",
                    "ua": "Myję się codziennie."
                },
                {
                    "en": "Myję się codziennie. (✓ ze wzmocnieniem)",
                    "ua": "Myję się codziennie."
                },
                {
                    "en": "On goli się rano. (✓)",
                    "ua": "Goli się rano."
                },
                {
                    "en": "Dziecko potrafi się umyć. (✓)",
                    "ua": "Dziecko potrafi już się umyć."
                }
            ],
            "note": "Mycie/golenie bez odruchu jest normą. Z odruchowym – dla podkreślenia."
        },
        {
            "label": "Kiedy obiektem jest inna osoba",
            "color": "purple",
            "description": "Jeśli działanie jest skierowane do <strong>innej osoby</strong> (nie do siebie) – NIE używaj odruchu.",
            "examples": [
                {
                    "en": "Umyła dziecko. (✓)",
                    "ua": "Umyła się."
                },
                {
                    "en": "Umyła się. (✓)",
                    "ua": "Umyła się (sama)."
                },
                {
                    "en": "Zraniłam moją przyjaciółkę. (✓)",
                    "ua": "Zraniłem przyjaciela."
                },
                {
                    "en": "Zraniłem siebie. (✓)",
                    "ua": "Zraniłem siebie."
                }
            ],
            "note": "Odruchowo tylko wtedy, gdy działam na SIEBIE, a nie na innych!"
        }
    ]
}

{
    "title": "6. Wzajemnie kontra refleksyjnie",
    "sections": [
        {
            "label": "Wzajemnie – siebie nawzajem (wzajemnie)",
            "color": "blue",
            "description": "<strong>Wzajemnie</strong> pokazuje wzajemne działanie (A → B i B → A). <strong>Odruchowe</strong> — działanie na siebie (A → A).",
            "examples": [
                {
                    "en": "Kochają się.",
                    "ua": "Kochają się. (wzajemnie)"
                },
                {
                    "en": "Kochają siebie.",
                    "ua": "Kochają siebie. (każdy sam)"
                },
                {
                    "en": "Pomagamy sobie nawzajem.",
                    "ua": "Pomagamy sobie nawzajem."
                },
                {
                    "en": "Pomagamy sobie.",
                    "ua": "Pomagamy sobie."
                }
            ],
            "note": "📌Wzajemnie = wzajemnie. Refleksyjny = do siebie."
        },
        {
            "label": "Przykłady różnicy",
            "color": "sky",
            "description": "Kontekst pokazuje różnicę:",
            "examples": [
                {
                    "en": "Patrzyli na siebie w lustrze.",
                    "ua": "Patrzyli na siebie w lustrze (wszyscy)."
                },
                {
                    "en": "Patrzyli na siebie siebie nawzajem.",
                    "ua": "Spojrzeli na siebie."
                },
                {
                    "en": "Porozmawiajcie ze sobą! (odruchowy)",
                    "ua": "Porozmawiajcie ze sobą!"
                },
                {
                    "en": "Porozmawiajcie ze sobą! (wzajemność)",
                    "ua": "Porozmawiajcie ze sobą!"
                }
            ]
        }
    ]
}

{
    "title": "7. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Wyjątkowo refleksyjny w dotyku, spotykaniu się, myciu.",
            "wrong": "Czuję się dobrze. / Spotkaliśmy się o 17:00.",
            "right": "​​​​ <span class="font-mono">Czuję się dobrze. / Spotkaliśmy się o 17.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Niepoprawna forma (on sam, on sam).",
            "wrong": "Sam to zrobił. / Dobrze się bawili.",
            "right": "​​​​ <span class="font-mono">Sam to zrobił. / Dobrze się bawili.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zamieszanie między sobą i sobą.",
            "wrong": "Kochają siebie. (kiedy razem)",
            "right": " ✅ <span class="font-mono">Kochają się.</span> (siebie)"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Pominięcie odruchu, gdy jest potrzebny.",
            "wrong": "Wczoraj zraniłem. / Uczyła hiszpańskiego.",
            "right": "​​​​ <span class="font-mono">Zraniłem się. / Sama nauczyła się hiszpańskiego.</span>"
        }
    ]
}

{
    "title": "9. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą formę",
    "select_intro": "Wpisz w puste miejsca właściwy zaimek zwrotny lub pozostaw puste.",
    "selects": [
        {
            "label": "Zraniłem ___ grając w piłkę nożną. (ja / ja)",
            "prompt": "W jakiej formie?"
        },
        {
            "label": "Uczyła ___ hiszpańskiego. (ona/ona)",
            "prompt": "Jaka forma?"
        },
        {
            "label": "Czuję się dziś ___ dobrze. (— / ja)",
            "prompt": "Potrzebujesz refleksu?"
        },
        {
            "label": "Świetnie się bawiliśmy ___ na imprezie. (my / my)",
            "prompt": "Jaka forma?"
        },
        {
            "label": "Poznali ___ na stacji. (— / siebie)",
            "prompt": "Wymagane odruchowy?"
        }
    ],
    "options": [
        "ja",
        "siebie",
        "siebie",
        "on rself",
        "siebie",
        "siebie",
        "]—"
    ],
    "input_title": "ćwiczenie 2. Wypełnij puste miejsca",
    "input_intro": "Wpisz poprawny zaimek zwrotny.",
    "inputs": [
        {
            "before": "Udało mi się ___. (ja)",
            "after": " →"
        },
        {
            "before": "Ona przecięła ___ nożem. (zacina się)",
            "after": " →"
        },
        {
            "before": "Przedstawili ___. (wprowadzono)",
            "after": "→"
        },
        {
            "before": "bawiliśmy się ___ na koncercie. (dobrze się bawiłem)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekta błędów",
    "rephrase_intro": "Znajdź i popraw błąd z zaimkami zwrotnymi.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Czuję się sobą dobrze.",
            "example_target": "Czuję się dobrze."
        },
        {
            "original": "1. Zrobił to sam.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Dobrze się bawili.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Spotkaliśmy się o 5.",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne strony z kategorii Zaimki i słowa orientacyjne",
    "items": [
        {
            "label": "Zaimki - Zaimki (przegląd)",
            "current": false
        },
        {
            "label": "Zaimki osobowe i przedmiotowe - osobowe i dopełnienia obiekt",
            "current": false
        },
        {
            "label": "Przymiotniki dzierżawcze a zaimki — mój / moje",
            "current": false
        },
        {
            "label": "Zaimki nieokreślone — ktoś, ktoś, nikt",
            "current": false
        },
        {
            "label": "Zaimki zwrotne — ja, ja, siebie (bieżące)",
            "current": true
        }
    ]
}
